import { createClient } from "@/lib/supabase/server";
import { notFound } from "next/navigation";
import { UserAvatar } from "@/components/UserAvatar";
import { FollowButton } from "@/components/FollowButton";
import { computeListSimilarity } from "@/lib/similarity";
import type { ListItemWithShow } from "../lists/actions";
import { UserListClient } from "./user-list-client";

export default async function UserProfilePage({
  params,
}: {
  params: Promise<{ username: string }>;
}) {
  const { username } = await params;
  const supabase = await createClient();

  const { data: profile } = await supabase
    .from("profiles")
    .select("*")
    .eq("username", username)
    .single();

  if (!profile) notFound();

  // Fetch the user's single list
  const { data: list } = await supabase
    .from("lists")
    .select("id, name, description, is_public")
    .eq("user_id", profile.id)
    .single();

  // Fetch list items (first 50, sorted by rating desc then position)
  let listItems: ListItemWithShow[] = [];
  let itemCount = 0;
  if (list) {
    const { data: itemsData, count } = await supabase
      .from("list_items")
      .select("*, shows(*)", { count: "exact" })
      .eq("list_id", list.id)
      .order("rating", { ascending: false, nullsFirst: false })
      .order("position", { ascending: true })
      .range(0, 49);
    listItems = (itemsData ?? []) as unknown as ListItemWithShow[];
    itemCount = count ?? listItems.length;
  }

  // Compute similarity with current user
  const {
    data: { user },
  } = await supabase.auth.getUser();

  let similarityScore: number | null = null;
  if (user && user.id !== profile.id && list?.is_public) {
    // Fetch viewer's list items
    const { data: viewerList } = await supabase
      .from("lists")
      .select("id")
      .eq("user_id", user.id)
      .single();

    if (viewerList) {
      const [viewerItems, profileItems] = await Promise.all([
        supabase
          .from("list_items")
          .select("show_id, rating, position")
          .eq("list_id", viewerList.id)
          .order("position", { ascending: true }),
        supabase
          .from("list_items")
          .select("show_id, rating, position")
          .eq("list_id", list.id)
          .order("position", { ascending: true }),
      ]);

      const listA = (viewerItems.data ?? []).map((i, idx) => ({
        showId: i.show_id,
        rating: i.rating,
        position: i.position ?? idx,
      }));
      const listB = (profileItems.data ?? []).map((i, idx) => ({
        showId: i.show_id,
        rating: i.rating,
        position: i.position ?? idx,
      }));

      similarityScore = computeListSimilarity(listA, listB);
    }
  }

  // Check if current user follows this profile
  let isFollowing = false;
  const isOwnProfile = user?.id === profile.id;
  if (user && !isOwnProfile) {
    const { data: follow } = await supabase
      .from("follows")
      .select("id")
      .eq("follower_id", user.id)
      .eq("following_id", profile.id)
      .maybeSingle();
    isFollowing = !!follow;
  }

  // Fetch the viewer's own show IDs so we can mark already-added shows
  let viewerShowIds: string[] = [];
  if (user && !isOwnProfile && list?.is_public) {
    const { data: viewerList } = await supabase
      .from("lists")
      .select("id")
      .eq("user_id", user.id)
      .single();
    if (viewerList) {
      const { data: viewerItems } = await supabase
        .from("list_items")
        .select("show_id")
        .eq("list_id", viewerList.id);
      viewerShowIds = (viewerItems ?? []).map((i) => i.show_id);
    }
  }

  return (
    <div>
      {/* User header */}
      <div className="mb-8 flex flex-wrap items-center gap-4">
        <UserAvatar
          url={profile.avatar_url}
          username={profile.username}
          size={56}
        />
        <div>
          <h1 className="text-xl font-semibold tracking-tight text-text-primary">
            @{profile.username}
          </h1>
          <p className="text-sm text-text-muted">{itemCount} shows</p>
        </div>
        <div className="ml-auto flex items-center gap-3">
          {similarityScore !== null && (
            <div className="flex items-center gap-1.5 rounded-full border border-accent/30 bg-accent-muted px-3 py-1.5">
              <span className="text-sm font-semibold text-accent">
                {similarityScore}%
              </span>
              <span className="text-xs text-text-muted">compatible</span>
            </div>
          )}
          {user && !isOwnProfile && (
            <FollowButton
              profileId={profile.id}
              initialFollowing={isFollowing}
            />
          )}
        </div>
      </div>

      {/* List */}
      {list?.is_public ? (
        <div>
          <div className="mb-3 flex items-center justify-between">
            <div>
              <h2 className="text-sm font-semibold text-text-primary">{list.name}</h2>
              {list.description && (
                <p className="mt-0.5 text-xs text-text-muted">{list.description}</p>
              )}
            </div>
            <span className="text-xs text-text-faint">{itemCount} shows</span>
          </div>

          {listItems.length === 0 ? (
            <p className="text-sm text-text-muted">No shows yet.</p>
          ) : (
            <div className="flex flex-col gap-1.5">
              {listItems.map((item, idx) => {
                const posterUrl = getPosterUrl(item.shows.poster_path, "w92");
                return (
                  <div
                    key={item.id}
                    className="flex items-center gap-2 md:gap-3 rounded-md border border-border bg-bg-surface p-2.5 md:p-3"
                  >
                    {/* Position */}
                    <span className="w-5 md:w-6 text-center font-mono text-xs font-bold text-text-muted tabular-nums shrink-0">
                      {idx + 1}
                    </span>

                    {/* Poster */}
                    <div className="relative h-12 w-8 shrink-0 overflow-hidden rounded-sm bg-bg-elevated">
                      {posterUrl ? (
                        <Image
                          src={posterUrl}
                          alt={item.shows.title}
                          fill
                          className="object-cover"
                          sizes="32px"
                        />
                      ) : (
                        <div className="flex h-full items-center justify-center">
                          <Television size={14} className="text-text-faint" />
                        </div>
                      )}
                    </div>

                    {/* Title */}
                    <span className="min-w-0 flex-1 truncate text-sm font-medium text-text-primary">
                      {item.shows.title}
                    </span>

                    {/* Rating */}
                    {item.rating != null && (
                      <span className="shrink-0 font-mono text-xs tabular-nums text-accent">
                        {item.rating}/10
                      </span>
                    )}
                  </div>
                );
              })}
              {itemCount > 50 && (
                <p className="mt-1 text-center text-xs text-text-faint">
                  Showing 50 of {itemCount} shows
                </p>
              )}
            </div>
          )}
        </div>
      ) : (
        <p className="text-sm text-text-muted">
          This user&apos;s list is private.
        </p>
      )}
    </div>
  );
}
